29→/**
30→ * Poll a task until it completes (fallback when WebSocket is not available).
31→ */
32→async function pollTask(taskId, onUpdate, intervalMs = 2000, maxAttempts = 300) {
33→    for (let i = 0; i < maxAttempts; i++) {
34→        try {
35→            const res = await safeFetch(`/api/task/${taskId}`);
36→            const data = await res.json();
37→            if (onUpdate) onUpdate(data);
38→
39→            if (data.status === 'completed' || data.status === 'failed' || data.status === 'cancelled') {
40→                return data;
41→            }
42→        } catch (e) {
43→            console.error('Poll error:', e);
44→        }
45→        await new Promise(r => setTimeout(r, intervalMs));
46→    }
47→    return null;
48→}

